const unclaimBroadcastGame = `-- name: UnclaimBroadcastGame :one
DELETE FROM broadcast_games
WHERE broadcast_id = $1 AND division = $2 AND round = $3 AND table_number = $4
RETURNING game_uuid
`

type UnclaimBroadcastGameParams struct {
	BroadcastID int32
	Division    string
	Round       int32
	TableNumber int32
}

func (q *Queries) UnclaimBroadcastGame(ctx context.Context, arg UnclaimBroadcastGameParams) (string, error) {
	row := q.db.QueryRow(ctx, unclaimBroadcastGame,
		arg.BroadcastID,
		arg.Division,
		arg.Round,
		arg.TableNumber,
	)
	var game_uuid string
	err := row.Scan(&game_uuid)
	return game_uuid, err
}

